import threading
import queue
import time
import random
from datetime import datetime

# Event queue for agent-manager communication
event_queue = queue.Queue()
alert_queue = queue.Queue()

class IDAAgent:
    """Intrusion Detection Agent base class"""
    def __init__(self, agent_id, agent_type, location):
        self.agent_id = agent_id
        self.agent_type = agent_type  # HIDS, NIDS, HYPERVISOR
        self.location = location
        self.is_running = False

    def generate_report(self):
        """Generate security report based on agent type"""
        raise NotImplementedError

    def send_to_manager(self, event):
        """Send event to global manager"""
        event_queue.put({
            'agent_id': self.agent_id,
            'agent_type': self.agent_type,
            'location': self.location,
            'event': event,
            'timestamp': datetime.now().isoformat()
        })

class HIDSAgent(IDAAgent):
    """Host-based IDS monitoring OS-level events"""
    def __init__(self, agent_id, vm_name):
        super().__init__(agent_id, 'HIDS', vm_name)

    def monitor_system_calls(self):
        """Simulate monitoring system calls for suspicious activity"""
        suspicious_patterns = ['execve', 'shell', 'buffer_overflow']
        events = ['open', 'read', 'write', 'close']

        # Random event generation (mostly normal)
        if random.random() < 0.1:  # 10% chance of suspicious event
            return {'type': 'SUSPICIOUS_SYSCALL', 
                    'pattern': random.choice(suspicious_patterns),
                    'risk_level': 'HIGH'}
        return {'type': 'NORMAL_SYSCALL', 'pattern': random.choice(events)}

class NIDSAgent(IDAAgent):
    """Network-based IDS monitoring network traffic"""
    def __init__(self, agent_id, location):
        super().__init__(agent_id, 'NIDS', location)

    def monitor_network_traffic(self):
        """Simulate network traffic analysis"""
        attack_signatures = ['SQL_INJECTION', 'XSS_ATTACK', 'PORT_SCAN']

        if random.random() < 0.15:  # 15% chance of detecting attack
            return {'type': 'NETWORK_ATTACK',
                    'signature': random.choice(attack_signatures),
                    'risk_level': 'CRITICAL',
                    'source_ip': f'192.168.{random.randint(1,255)}.1'}
        return {'type': 'NORMAL_TRAFFIC', 'bytes': random.randint(100, 10000)}

class GlobalIDSManager:
    """Global Intrusion Detection Manager - correlates events from all agents"""

    def __init__(self):
        self.correlation_window = []
        self.threat_database = {}

    def correlate_events(self):
        """Correlate events from multiple agents to identify coordinated attacks"""
        while True:
            try:
                event = event_queue.get(timeout=1)
                self.process_event(event)
            except queue.Empty:
                time.sleep(0.1)

    def process_event(self, event):
        """Process individual event and check for correlation"""
        event_data = event['event']

        # High risk event from any agent
        if isinstance(event_data, dict) and event_data.get('risk_level') in ['HIGH', 'CRITICAL']:
            alert = f"ALERT [{event['agent_type']}]: {event_data.get('type', 'UNKNOWN')} " \
                    f"at {event['location']} - Risk: {event_data.get('risk_level')}"
            print(f"[GIDM] {alert}")
            alert_queue.put(alert)

        # Store for correlation analysis
        self.correlation_window.append(event)

        # Keep only recent events (last 100)
        if len(self.correlation_window) > 100:
            self.correlation_window.pop(0)

def run_agent(agent):
    """Run agent monitoring loop"""
    while agent.is_running:
        event = agent.monitor_system_calls() if agent.agent_type == 'HIDS' else agent.monitor_network_traffic()
        agent.send_to_manager(event)
        time.sleep(random.uniform(0.5, 1.5))

# Main simulation
def simulate_dids():
    print("=== Distributed IDS Simulation ===\n")

    # Create agents
    agents = [
        HIDSAgent('HIDS-001', 'VM-WebServer-1'),
        HIDSAgent('HIDS-002', 'VM-Database-1'),
        NIDSAgent('NIDS-001', 'Virtual-Switch-1'),
        NIDSAgent('NIDS-002', 'Gateway-Router')
    ]

    # Start manager in separate thread
    manager = GlobalIDSManager()
    manager_thread = threading.Thread(target=manager.correlate_events, daemon=True)
    manager_thread.start()

    # Start all agents
    for agent in agents:
        agent.is_running = True
        thread = threading.Thread(target=run_agent, args=(agent,), daemon=True)
        thread.start()

    # Run simulation for 10 seconds
    print("Monitoring started. Simulating distributed detection...\n")
    time.sleep(10)

    # Stop agents
    for agent in agents:
        agent.is_running = False

    print("\n=== Simulation Complete ===")

if __name__ == "__main__":
    simulate_dids()

#include <stdio.h>
#include <string.h>
#include <stdlib.h>

// Attack signature database
typedef struct {
    char name[50];
    char signature[100];
    char severity[20];
} AttackSignature;

AttackSignature signatures[] = {
    {"SQL Injection", "' OR '1'='1", "CRITICAL"},
    {"SQL Injection", "'; DROP TABLE", "CRITICAL"},
    {"XSS Attack", "<script>", "HIGH"},
    {"XSS Attack", "javascript:", "HIGH"},
    {"Command Injection", "; rm -rf", "CRITICAL"},
    {"Command Injection", "| /bin/sh", "CRITICAL"},
    {"Path Traversal", "../..", "MEDIUM"},
    {"Buffer Overflow", "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA", "HIGH"}
};

#define NUM_SIGNATURES (sizeof(signatures) / sizeof(AttackSignature))

// Log entry structure
typedef struct {
    char timestamp[30];
    char source_ip[20];
    char payload[256];
} LogEntry;

// Simple string search (substring matching)
int contains_signature(char *payload, char *signature) {
    return strstr(payload, signature) != NULL;
}

// Signature-based detection function
int detect_intrusion(LogEntry *log, char *matched_signature, char *attack_name) {
    for (int i = 0; i < NUM_SIGNATURES; i++) {
        if (contains_signature(log->payload, signatures[i].signature)) {
            strcpy(matched_signature, signatures[i].signature);
            strcpy(attack_name, signatures[i].name);
            return 1;  // Attack detected
        }
    }
    return 0;  // No attack detected
}

// Simulate log generation
void generate_sample_log(LogEntry *log, int scenario) {
    strcpy(log->timestamp, "2024-01-15 14:32:15");
    strcpy(log->source_ip, "192.168.1.100");

    switch(scenario) {
        case 0:  // Normal request
            strcpy(log->payload, "GET /index.html HTTP/1.1\nHost: example.com");
            break;
        case 1:  // SQL Injection
            strcpy(log->payload, "GET /login?user=admin' OR '1'='1 HTTP/1.1");
            break;
        case 2:  // XSS Attack
            strcpy(log->payload, "GET /comment?text=<script>alert('xss')</script> HTTP/1.1");
            break;
        case 3:  // Path Traversal
            strcpy(log->payload, "GET /../../etc/passwd HTTP/1.1");
            break;
    }
}

int main() {
    printf("=== Signature-Based Intrusion Detection System ===\n\n");

    printf("Loaded %d attack signatures into database\n\n", NUM_SIGNATURES);

    // Test scenarios
    char *scenarios[] = {"Normal Request", "SQL Injection", "XSS Attack", "Path Traversal"};

    for (int i = 0; i < 4; i++) {
        LogEntry log;
        generate_sample_log(&log, i);

        char matched_sig[100] = {0};
        char attack_name[50] = {0};

        printf("--- Test Case %d: %s ---\n", i + 1, scenarios[i]);
        printf("Source IP: %s\n", log.source_ip);
        printf("Payload: %s\n", log.payload);

        if (detect_intrusion(&log, matched_sig, attack_name)) {
            printf("[ALERT] Intrusion Detected!\n");
            printf("  Attack Type: %s\n", attack_name);
            printf("  Matched Signature: %s\n", matched_sig);
            printf("  Severity: %s\n\n", 
                   strstr(matched_sig, "OR") || strstr(matched_sig, "DROP") ? "CRITICAL" :
                   strstr(matched_sig, "<script>") ? "HIGH" : "MEDIUM");
        } else {
            printf("[OK] No threats detected\n\n");
        }
    }

    printf("=== Detection Complete ===\n");
    return 0;
}
